failure_code = #{failureCode}, device_part_code = #{devicePartCode}, device_part_name = #{devicePartName}, failure_name = #{failureName}, failure_phenomenon = #{failurePhenomenon}, failure_description = #{failureDescription}, failure_notice_type = #{failureNoticeType}, failure_type = #{failureType}, failure_start_time = #{failureStartTime}, status = #{status}, updated_at = #{updatedAt},
