mapper.select:
SELECT id, failure_code AS failureCode, device_part_code AS devicePartCode, device_part_name AS devicePartName, failure_name AS failureName, failure_phenomenon AS failurePhenomenon, failure_description AS failureDescription, failure_notice_type AS failureNoticeType, failure_type AS failureType, failure_start_time AS failureStartTime, status, creator_username AS creatorUsername, creator_name AS creatorName, created_at AS createdAt, updated_at AS updatedAt FROM failure_record
AND creator_username = #{creatorUsername}
AND failure_code LIKE CONCAT('%', #{failureCode}, '%')
AND device_part_code LIKE CONCAT('%', #{devicePartCode}, '%')
AND failure_name LIKE CONCAT('%', #{failureName}, '%')
AND DATE(failure_start_time) = #{failureStartTime}
AND status = #{status}
AND failure_type = #{failureType}
ORDER BY id DESC

